            builder.Append("Version=");
            builder.Append('\'').Append(GetVersion()).Append('\'');
            builder.Append('|');
            builder.Append("SystemInfo=");
            builder.Append('\'').Append(GetSystemInfo()).Append('\'');
            builder.Append('|');
            builder.Append("AuthCode=");
            builder.Append('\'').Append(GetAuthCode()).Append('\'');

            this.Limit = originalLimit;

        }
    }
}
